import React, { useState, useEffect } from "react";
import Nav from "../Nav/Nav";
import "./NewReservation.css";

function NewReservation() {
  const [formData, setFormData] = useState({
    cinema: "",
    movie: "",
    movie_key: "",
    date: "",
    time: "",
    advertisement_slots: [],
    name: "",
    email: "",
    phone: "",
    company: "",
    advertisement_duration: "",
    notes: ""
  });

  const [step, setStep] = useState(1);
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [reservationId, setReservationId] = useState(null);

  const timeSlots = [
    "10:00 AM", "1:00 PM", "4:00 PM", "7:00 PM", "10:00 PM"
  ];

  // Fetch cinemas from API
  useEffect(() => {
    const fetchCinemas = async () => {
      try {
        setLoading(true);
        const response = await fetch('http://localhost:5000/api/cinemas');
        const data = await response.json();
        
        if (data.success) {
          setCinemas(data.data);
        } else {
          console.error('Error fetching cinemas:', data.message);
        }
      } catch (error) {
        console.error('Error fetching cinemas:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchCinemas();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleMovieChange = (e) => {
    const selectedMovie = e.target.value;
    const movieData = selectedMovie.split('|');
    
    setFormData(prev => ({
      ...prev,
      movie: movieData[1] || '',
      movie_key: movieData[0] || '',
      advertisement_slots: [] // Reset slots when movie changes
    }));
  };

  const handleNext = () => {
    if (step < 4) {
      setStep(step + 1);
    }
  };

  const handlePrev = () => {
    if (step > 1) {
      setStep(step - 1);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    
    try {
      const response = await fetch('http://localhost:5000/api/reservations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          cinema_id: formData.cinema,
          movie_name: formData.movie,
          movie_key: formData.movie_key,
          show_date: formData.date,
          show_time: formData.time,
          advertisement_slots: formData.advertisement_slots,
          advertisement_duration: parseInt(formData.advertisement_duration),
          customer_name: formData.name,
          customer_email: formData.email,
          customer_phone: formData.phone,
          company_name: formData.company,
          notes: formData.notes
        })
      });

      const data = await response.json();
      
      if (data.success) {
        setReservationId(data.data.reservation_id);
        setStep(5); // Go to confirmation step
      } else {
        alert('Error creating reservation: ' + data.message);
      }
    } catch (error) {
      console.error('Error creating reservation:', error);
      alert('Error creating reservation. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  // Get available movies based on selected cinema
  const getAvailableMovies = () => {
    const selectedCinema = cinemas.find(cinema => cinema._id === formData.cinema);
    if (selectedCinema) {
      const movies = [];
      const ongoingMovies = selectedCinema.ongoing_movies;
      
      if (ongoingMovies.movie_1 && ongoingMovies.movie_1.name) {
        movies.push({ key: 'movie_1', name: ongoingMovies.movie_1.name });
      }
      if (ongoingMovies.movie_2 && ongoingMovies.movie_2.name) {
        movies.push({ key: 'movie_2', name: ongoingMovies.movie_2.name });
      }
      if (ongoingMovies.movie_3 && ongoingMovies.movie_3.name) {
        movies.push({ key: 'movie_3', name: ongoingMovies.movie_3.name });
      }
      if (ongoingMovies.movie_4 && ongoingMovies.movie_4.name) {
        movies.push({ key: 'movie_4', name: ongoingMovies.movie_4.name });
      }
      
      return movies;
    }
    return [];
  };

  // Get advertisement slots for selected cinema and movie
  const getAdvertisementSlots = () => {
    if (!formData.cinema || !formData.movie_key) return { starting: [], interval: [], ending: [] };
    
    const selectedCinema = cinemas.find(cinema => cinema._id === formData.cinema);
    if (!selectedCinema || !selectedCinema.movie_slot_pricing || !selectedCinema.movie_slot_pricing[formData.movie_key]) {
      return { starting: [], interval: [], ending: [] };
    }
    
    const movieSlots = selectedCinema.movie_slot_pricing[formData.movie_key].slots || [];
    
    return {
      starting: movieSlots.filter(slot => slot.slot_type === 'starting'),
      interval: movieSlots.filter(slot => slot.slot_type === 'interval'),
      ending: movieSlots.filter(slot => slot.slot_type === 'ending')
    };
  };

  // Handle slot selection
  const handleSlotSelection = (slotType, slotNumber, price) => {
    const slotId = `${slotType}_${slotNumber}`;
    const isSelected = formData.advertisement_slots.some(slot => slot.slot_id === slotId);
    
    if (isSelected) {
      setFormData(prev => ({
        ...prev,
        advertisement_slots: prev.advertisement_slots.filter(slot => slot.slot_id !== slotId)
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        advertisement_slots: [...prev.advertisement_slots, {
          slot_id: slotId,
          slot_type: slotType,
          slot_number: slotNumber,
          price: price
        }]
      }));
    }
  };

  // Calculate total amount
  const calculateTotal = () => {
    return formData.advertisement_slots.reduce((sum, slot) => sum + slot.price, 0);
  };

  const renderStep1 = () => (
    <div className="step-content">
      <h3>Select Cinema & Movie</h3>
      
      <div className="form-group">
        <label>Cinema *</label>
        {loading ? (
          <div className="loading">Loading cinemas...</div>
        ) : (
          <select 
            name="cinema" 
            value={formData.cinema} 
            onChange={handleInputChange}
            required
          >
            <option value="">Choose a cinema</option>
            {cinemas.map(cinema => (
              <option key={cinema._id} value={cinema._id}>
                {cinema.cinema_name} - {cinema.cinema_location}
              </option>
            ))}
          </select>
        )}
      </div>
      
      <div className="form-group">
        <label>Movie *</label>
        <select 
          name="movie" 
          value={`${formData.movie_key}|${formData.movie}`} 
          onChange={handleMovieChange}
          required
          disabled={!formData.cinema}
        >
          <option value="">Choose a movie</option>
          {getAvailableMovies().map(movie => (
            <option key={movie.key} value={`${movie.key}|${movie.name}`}>{movie.name}</option>
          ))}
        </select>
        {!formData.cinema && (
          <p className="help-text">Please select a cinema first</p>
        )}
      </div>
    </div>
  );

  const renderStep2 = () => {
    const slots = getAdvertisementSlots();
    const totalPrice = calculateTotal();
    
    return (
      <div className="step-content">
        <h3>Select Advertisement Slots</h3>
        
        <div className="form-group">
          <label>Date *</label>
          <input
            type="date"
            name="date"
            value={formData.date}
            onChange={handleInputChange}
            min={new Date().toISOString().split('T')[0]}
            required
          />
        </div>
        
        <div className="form-group">
          <label>Time *</label>
          <select 
            name="time" 
            value={formData.time} 
            onChange={handleInputChange}
            required
          >
            <option value="">Choose a time</option>
            {timeSlots.map(time => (
              <option key={time} value={time}>{time}</option>
            ))}
          </select>
        </div>

        <div className="advertisement-slots-section">
          <h4>Advertisement Slots Available</h4>
          
          {/* Starting Slots */}
          <div className="slot-category">
            <h5>Starting Slots (Before Movie)</h5>
            <div className="slots-grid">
              {slots.starting.map((slot, index) => (
                <div 
                  key={`starting_${slot.slot_number}`}
                  className={`slot-item ${slot.is_reserved ? 'reserved' : 'available'} ${
                    formData.advertisement_slots.some(s => s.slot_id === `starting_${slot.slot_number}`) ? 'selected' : ''
                  }`}
                  onClick={() => !slot.is_reserved && handleSlotSelection('starting', slot.slot_number, slot.price)}
                >
                  <div className="slot-number">Slot {slot.slot_number}</div>
                  <div className="slot-price">₹{slot.price}</div>
                  <div className="slot-status">
                    {slot.is_reserved ? 'Reserved' : 'Available'}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Interval Slots */}
          <div className="slot-category">
            <h5>Interval Slots (During Movie)</h5>
            <div className="slots-grid">
              {slots.interval.map((slot, index) => (
                <div 
                  key={`interval_${slot.slot_number}`}
                  className={`slot-item ${slot.is_reserved ? 'reserved' : 'available'} ${
                    formData.advertisement_slots.some(s => s.slot_id === `interval_${slot.slot_number}`) ? 'selected' : ''
                  }`}
                  onClick={() => !slot.is_reserved && handleSlotSelection('interval', slot.slot_number, slot.price)}
                >
                  <div className="slot-number">Slot {slot.slot_number}</div>
                  <div className="slot-price">₹{slot.price}</div>
                  <div className="slot-status">
                    {slot.is_reserved ? 'Reserved' : 'Available'}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Ending Slots */}
          <div className="slot-category">
            <h5>Ending Slots (After Movie)</h5>
            <div className="slots-grid">
              {slots.ending.map((slot, index) => (
                <div 
                  key={`ending_${slot.slot_number}`}
                  className={`slot-item ${slot.is_reserved ? 'reserved' : 'available'} ${
                    formData.advertisement_slots.some(s => s.slot_id === `ending_${slot.slot_number}`) ? 'selected' : ''
                  }`}
                  onClick={() => !slot.is_reserved && handleSlotSelection('ending', slot.slot_number, slot.price)}
                >
                  <div className="slot-number">Slot {slot.slot_number}</div>
                  <div className="slot-price">₹{slot.price}</div>
                  <div className="slot-status">
                    {slot.is_reserved ? 'Reserved' : 'Available'}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {formData.advertisement_slots.length > 0 && (
            <div className="selected-slots-summary">
              <h5>Selected Slots ({formData.advertisement_slots.length})</h5>
              <div className="selected-slots-list">
                {formData.advertisement_slots.map(slot => (
                  <div key={slot.slot_id} className="selected-slot">
                    {slot.slot_type.charAt(0).toUpperCase() + slot.slot_type.slice(1)} Slot {slot.slot_number} - ₹{slot.price}
                  </div>
                ))}
              </div>
              <div className="total-price">
                <strong>Total: ₹{totalPrice}</strong>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderStep3 = () => (
    <div className="step-content">
      <h3>Advertisement Details</h3>
      <div className="form-group">
        <label>Full Name *</label>
        <input
          type="text"
          name="name"
          value={formData.name}
          onChange={handleInputChange}
          required
        />
      </div>
      
      <div className="form-group">
        <label>Company Name *</label>
        <input
          type="text"
          name="company"
          value={formData.company}
          onChange={handleInputChange}
          required
        />
      </div>
      
      <div className="form-group">
        <label>Email *</label>
        <input
          type="email"
          name="email"
          value={formData.email}
          onChange={handleInputChange}
          required
        />
      </div>
      
      <div className="form-group">
        <label>Phone Number *</label>
        <input
          type="tel"
          name="phone"
          value={formData.phone}
          onChange={handleInputChange}
          required
        />
      </div>

      <div className="form-group">
        <label>Advertisement Duration *</label>
        <select 
          name="advertisement_duration" 
          value={formData.advertisement_duration} 
          onChange={handleInputChange}
          required
        >
          <option value="">Select duration</option>
          <option value="15">15 seconds</option>
          <option value="30">30 seconds</option>
          <option value="45">45 seconds</option>
          <option value="60">1 minute</option>
          <option value="90">1.5 minutes</option>
          <option value="120">2 minutes</option>
        </select>
      </div>

      <div className="form-group">
        <label>Additional Notes</label>
        <textarea
          name="notes"
          value={formData.notes}
          onChange={handleInputChange}
          rows="3"
          placeholder="Any special requirements or notes..."
        />
      </div>

      {formData.advertisement_slots.length > 0 && (
        <div className="booking-summary">
          <h4>Booking Summary</h4>
          <div className="summary-details">
            <p><strong>Cinema:</strong> {cinemas.find(c => c._id === formData.cinema)?.cinema_name}</p>
            <p><strong>Movie:</strong> {formData.movie}</p>
            <p><strong>Date:</strong> {formData.date}</p>
            <p><strong>Time:</strong> {formData.time}</p>
            <p><strong>Selected Slots:</strong> {formData.advertisement_slots.length}</p>
            <p><strong>Total Price:</strong> ₹{calculateTotal()}</p>
          </div>
        </div>
      )}
    </div>
  );

  const renderStep4 = () => {
    const selectedCinema = cinemas.find(c => c._id === formData.cinema);
    const totalAmount = calculateTotal();
    
    return (
      <div className="step-content">
        <h3>Reservation Summary</h3>
        
        <div className="summary-container">
          <div className="summary-section">
            <h4>Cinema Details</h4>
            <p><strong>Cinema:</strong> {selectedCinema?.cinema_name || 'N/A'}</p>
            <p><strong>Location:</strong> {selectedCinema?.cinema_location || 'N/A'}</p>
          </div>
          
          <div className="summary-section">
            <h4>Movie Details</h4>
            <p><strong>Movie:</strong> {formData.movie}</p>
            <p><strong>Show Date:</strong> {formData.date}</p>
            <p><strong>Show Time:</strong> {formData.time}</p>
          </div>
          
          <div className="summary-section">
            <h4>Advertisement Details</h4>
            <p><strong>Duration:</strong> {formData.advertisement_duration} seconds</p>
            <p><strong>Selected Slots:</strong> {formData.advertisement_slots.length}</p>
            
            <div className="slots-breakdown">
              <h5>Slot Breakdown:</h5>
              {formData.advertisement_slots.map(slot => (
                <div key={slot.slot_id} className="slot-item-summary">
                  {slot.slot_type.charAt(0).toUpperCase() + slot.slot_type.slice(1)} Slot {slot.slot_number} - ₹{slot.price}
                </div>
              ))}
            </div>
          </div>
          
          <div className="summary-section">
            <h4>Customer Details</h4>
            <p><strong>Name:</strong> {formData.name}</p>
            <p><strong>Company:</strong> {formData.company}</p>
            <p><strong>Email:</strong> {formData.email}</p>
            <p><strong>Phone:</strong> {formData.phone}</p>
            {formData.notes && (
              <p><strong>Notes:</strong> {formData.notes}</p>
            )}
          </div>
          
          <div className="summary-section total-section">
            <h4>Total Amount</h4>
            <div className="total-amount">₹{totalAmount}</div>
          </div>
        </div>
      </div>
    );
  };

  const renderStep5 = () => {
    return (
      <div className="step-content">
        <div className="confirmation-container">
          <div className="success-icon">✓</div>
          <h3>Reservation Confirmed!</h3>
          <p>Your advertisement slot reservation has been successfully created.</p>
          
          <div className="reservation-details">
            <h4>Reservation Details</h4>
            <p><strong>Reservation ID:</strong> {reservationId}</p>
            <p><strong>Status:</strong> Pending Confirmation</p>
            <p><strong>Total Amount:</strong> ₹{calculateTotal()}</p>
          </div>
          
          <div className="next-steps">
            <h4>What's Next?</h4>
            <ul>
              <li>You will receive a confirmation email shortly</li>
              <li>Our team will review your reservation</li>
              <li>Payment instructions will be sent via email</li>
              <li>You can track your reservation status in "My Reservations"</li>
            </ul>
          </div>
          
          <div className="confirmation-actions">
            <a href="/my-reservations" className="btn-primary">
              View My Reservations
            </a>
            <a href="/new-reservation" className="btn-secondary">
              Make Another Reservation
            </a>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div>
      {/* Navbar */}
      <Nav />

      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>Book Advertisement Slots</h1>
          <p>Reserve advertisement slots for your business in cinema halls</p>
        </div>
      </section>

      {/* Reservation Form */}
      <section className="reservation-section">
        <div className="container">
          <div className="reservation-form">
            <div className="form-header">
              <h2>Make a Reservation</h2>
              <div className="step-indicator">
                <div className={`step ${step >= 1 ? 'active' : ''}`}>1</div>
                <div className={`step ${step >= 2 ? 'active' : ''}`}>2</div>
                <div className={`step ${step >= 3 ? 'active' : ''}`}>3</div>
                <div className={`step ${step >= 4 ? 'active' : ''}`}>4</div>
                <div className={`step ${step >= 5 ? 'active' : ''}`}>5</div>
              </div>
              <div className="step-labels">
                <span>Cinema & Movie</span>
                <span>Select Slots</span>
                <span>Details</span>
                <span>Summary</span>
                <span>Confirm</span>
              </div>
            </div>

            <form onSubmit={handleSubmit}>
              {step === 1 && renderStep1()}
              {step === 2 && renderStep2()}
              {step === 3 && renderStep3()}
              {step === 4 && renderStep4()}
              {step === 5 && renderStep5()}

              {step < 5 && (
                <div className="form-actions">
                  {step > 1 && (
                    <button type="button" onClick={handlePrev} className="btn-secondary">
                      Previous
                    </button>
                  )}
                  {step < 4 ? (
                    <button type="button" onClick={handleNext} className="btn-primary">
                      Next
                    </button>
                  ) : (
                    <button type="submit" className="btn-primary" disabled={submitting}>
                      {submitting ? 'Creating Reservation...' : 'Complete Reservation'}
                    </button>
                  )}
                </div>
              )}
            </form>
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <h3>D&S Creations</h3>
            <p>Your premier destination for cinema advertising and entertainment.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul>
              <li><a href="/mainhome">Home</a></li>
              <li><a href="/new-reservation">New Reservation</a></li>
              <li><a href="/my-reservations">My Reservations</a></li>
              <li><a href="/conus">Contact Us</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Contact Info</h4>
            <p>Email: info@dscreations.com</p>
            <p>Phone: +1 (555) 123-4567</p>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; {new Date().getFullYear()} D&S Creations. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
}

export default NewReservation;
